# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit
import MobileCoreServices
import SafariServices

class ViewController: UIViewController {
    var applicationDelegate: UIApplicationDelegate?

    override func viewDidLoad() {
        super.viewDidLoad()
        let url = URL(string: "https://myapp.com/promo?code=XYZ&discount=50")!
        openURL(url: url)
        applicationDelegate = UIApplication.shared.delegate as? AppDelegate
    }

    func openURL(url: URL) {
        let activityViewController = SFSafariViewController(url: url)
        present(activityViewController, animated: true, completion: nil)

        guard let items = activityViewController.content! as? [AnyObject],
              let urlItems = items as? [URL],
              let targetItem = urlItems.first else { return }

        if handlePromoURL(url: targetItem) {
            activityViewController.dismiss(animated: true, completion: nil)
        }
    }

    func handlePromoURL(url: URL) -> Bool {
        guard let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: false)?.queryItems else { return false }

        for item in queryItems {
            if item.name == "code" {
                UserDefaults.standard.set(item.value, forKey: "promoCode")
            } else if item.name == "discount" {
                let discount = Double(item.value)! / 100.0
                UserDefaults.standard.set(discount, forKey: "discountPercentage")
            }
        }

        // Apply the promo code and discount percentage to the user account here

        return true
    }
}